.darma-loader-darma-custom-079 {
  display: inline-flex;
  width: 90px;
  aspect-ratio: 2;
  animation: darma-loader-darma-custom-079-l11-0 1s linear infinite;
}
.darma-loader-darma-custom-079:before,
.darma-loader-darma-custom-079:after {
  content: "";
  flex: 1;
  background: var(--loader-color, #574951);
  clip-path: polygon(50% 0,100% 50%,50% 100%,0 50%);
  animation: darma-loader-darma-custom-079-l11-1 1s linear infinite;
  transform-origin: right;
}
.darma-loader-darma-custom-079:after {
  scale: -1.6 1.6;
  translate: -100% 0;
  background: var(--loader-secondary-color, #83988e);
  clip-path: polygon(100% 50%,81.17% 89.09%,38.87% 98.75%,4.95% 71.69%,4.95% 28.31%,38.87% 1.25%,81.17% 10.91%);
  animation: darma-loader-darma-custom-079-l11-2 1s linear infinite;
}
@keyframes darma-loader-darma-custom-079-l11-0 {
  0%{translate: 0 -35.35%}
  to{translate: 0  35.35%}
}
@keyframes darma-loader-darma-custom-079-l11-1 {
  0%{rotate: -45deg}
  to{rotate:  45deg}
}
@keyframes darma-loader-darma-custom-079-l11-2 {
  0%{rotate:  25.7deg}
  to{rotate: -25.7deg}
}

